DROP INDEX IF EXISTS "idx_partners_logo_strip_public";--> statement-breakpoint
DROP INDEX IF EXISTS "idx_partners_logo_strip_full_proof";--> statement-breakpoint
CREATE INDEX "idx_partners_logo_strip_public" ON "partners" USING btree ("sort_order","name") WHERE "partners"."is_active" = true AND "partners"."is_published" = true AND "partners"."show_in_logo_strip" = true AND "partners"."logo_url" IS NOT NULL AND "partners"."logo_usage_approved_at" IS NOT NULL AND "partners"."logo_usage_approved_by" IS NOT NULL AND btrim("partners"."logo_usage_approved_by") <> '' AND "partners"."logo_usage_scope" IS NOT NULL AND btrim("partners"."logo_usage_scope") <> '';
